#include <stdio.h>
int main() {
    int T, n, a[100], i, j, count;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        count = 0;
        for (i = 0; i < n; i++) {
            for (j = 0; j < i; j++) {
                if (a[i] == a[j]) break;
            }
            if (j == i) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

