import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = scanner.nextInt();
            }
            int count = 0;
            for (int i = 0; i < n; i++) {
                boolean found = false;
                for (int j = 0; j < i; j++) {
                    if (a[i] == a[j]) {
                        found = true;
                        break;
                    }
                }
                if (!found) count++;
            }
            System.out.println(count);
        }
    }
}

