def solve(n, a):
    count = 0
    for i in range(n):
        found = False
        for j in range(i):
            if a[i] == a[j]:
                found = True
                break
        if not found: count += 1
    return count

t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))
    print(solve(n, a))

